SELECT p.year, AVG(p.ticket_sales) AS average_ticket_sales
FROM productions p
GROUP BY p.year;

SELECT user_id, MAX(login_time) AS latest_login
FROM logins
GROUP BY user_id;

SELECT production_name, year, budget, ticket_sales, rating
FROM productions
WHERE rating = (SELECT MAX(rating) FROM productions);

SELECT user_id
FROM logins
WHERE success = 0;
